// src/index.js
import React from 'react';
import ReactDOM from 'react-dom';
import App from './App'; // Import component chính App
import { BrowserRouter } from 'react-router-dom';
import './styles/global.css'; // Import CSS toàn cục

ReactDOM.render(
  <React.StrictMode>
    <BrowserRouter>
      <App />
    </BrowserRouter>
  </React.StrictMode>,
  document.getElementById('root') // Gắn vào phần tử "root" trong index.html
);
